using ContosoUniversity.Data;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Hosting;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.FileProviders;
using Microsoft.Extensions.Logging;
using System;

namespace ContosoUniversity.Tests;

internal static class TestHelpers
{
    public static SchoolContext CreateContext(string dbName = null)
    {
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
            .Options;
        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static void DrainNotificationQueue()
    {
        using var service = new NotificationService();
        while (service.ReceiveNotification() != null) { }
    }
}

internal sealed class FakeWebHostEnvironment : IWebHostEnvironment
{
    public string WebRootPath { get; set; } = "";
    public string ContentRootPath { get; set; } = "";
    public IFileProvider WebRootFileProvider { get; set; }
    public IFileProvider ContentRootFileProvider { get; set; }
    public string EnvironmentName { get; set; } = "Testing";
    public string ApplicationName { get; set; } = "ContosoUniversity";
}

internal sealed class FakeLogger<T> : ILogger<T>
{
    public IDisposable BeginScope<TState>(TState state) where TState : notnull => NullDisposable.Instance;
    public bool IsEnabled(LogLevel logLevel) => false;
    public void Log<TState>(LogLevel logLevel, EventId eventId, TState state, Exception exception, Func<TState, Exception, string> formatter) { }

    private sealed class NullDisposable : IDisposable
    {
        public static readonly NullDisposable Instance = new();
        public void Dispose() { }
    }
}

