using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class NotificationServiceTests
{
    private NotificationService _sut;

    [TestInitialize]
    public void Setup()
    {
        // Drain shared static queue to prevent test interference
        TestHelpers.DrainNotificationQueue();
        _sut = new NotificationService();
    }

    [TestCleanup]
    public void Cleanup()
    {
        _sut?.Dispose();
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_CreatesCorrectMessage()
    {
        // Act
        _sut.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("1", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("New Student 'John Doe' has been created", notification.Message);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Act
        _sut.SendNotification("Course", "42", EntityOperation.UPDATE, "Teacher");

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 42) has been updated", notification.Message);
        Assert.AreEqual("Teacher", notification.CreatedBy);
    }

    [TestMethod]
    public void SendNotification_NullUserName_DefaultsToSystem()
    {
        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE, null);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "New Department 'Math' has been created", DisplayName = "CREATE operation")]
    [DataRow(EntityOperation.UPDATE, "Department 'Math' has been updated", DisplayName = "UPDATE operation")]
    [DataRow(EntityOperation.DELETE, "Department 'Math' has been deleted", DisplayName = "DELETE operation")]
    public void SendNotification_DifferentOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
    {
        // Act
        _sut.SendNotification("Department", "1", "Math", operation);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual(expectedMessage, notification.Message);
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Act
        var result = _sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        _sut.SendNotification("A", "1", EntityOperation.CREATE);
        _sut.SendNotification("B", "2", EntityOperation.UPDATE);

        // Act & Assert
        var first = _sut.ReceiveNotification();
        Assert.AreEqual("A", first.EntityType);
        Assert.AreEqual("1", first.EntityId);

        var second = _sut.ReceiveNotification();
        Assert.AreEqual("B", second.EntityType);
        Assert.AreEqual("2", second.EntityId);

        Assert.IsNull(_sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Act - MarkAsRead is a no-op but should not throw
        _sut.MarkAsRead(1);
        _sut.MarkAsRead(999);
        _sut.MarkAsRead(0);
    }

    [TestMethod]
    public void Dispose_CanBeCalledMultipleTimes()
    {
        // Act - should not throw on double dispose
        _sut.Dispose();
        _sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_WhitespaceDisplayName_UsesIdFallback()
    {
        // Act
        _sut.SendNotification("Student", "5", "   ", EntityOperation.DELETE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student (ID: 5) has been deleted", notification.Message);
    }

    [TestMethod]
    public void SendNotification_NullDisplayName_UsesIdFallback()
    {
        // Act
        _sut.SendNotification("Course", "10", null, EntityOperation.UPDATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Course (ID: 10) has been updated", notification.Message);
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        _sut.SendNotification("Student", "1", EntityOperation.CREATE);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before, "CreatedAt should be recent");
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1), "CreatedAt should not be in the future");
    }

    [TestMethod]
    public void SendNotification_DefaultOperation_GeneratesFallbackMessage()
    {
        // Arrange - cast an invalid int to EntityOperation to trigger the default switch case
        var unknownOp = (EntityOperation)999;

        // Act
        _sut.SendNotification("Item", "1", "Widget", unknownOp);

        // Assert
        var notification = _sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("Item 'Widget'"));
        Assert.IsTrue(notification.Message.Contains("999"));
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_SetsPropertiesAndAddsItems()
    {
        // Arrange & Act
        var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

        // Assert
        Assert.AreEqual(2, list.PageIndex);
        Assert.AreEqual(4, list.TotalPages); // ceil(10/3) = 4
        Assert.AreEqual(3, list.Count);
        Assert.AreEqual(1, list[0]);
        Assert.AreEqual(2, list[1]);
        Assert.AreEqual(3, list[2]);
    }

    [TestMethod]
    [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 → 4 pages")]
    [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 → 2 pages")]
    [DataRow(10, 10, 1, DisplayName = "10 items, page size 10 → 1 page")]
    [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 → 1 page")]
    [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 → 3 pages")]
    [DataRow(0, 5, 0, DisplayName = "0 items, page size 5 → 0 pages")]
    public void Constructor_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Act
        var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, list.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_PageOne_ReturnsFalse()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.IsFalse(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_PageTwo_ReturnsTrue()
    {
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.IsTrue(list.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_LastPage_ReturnsFalse()
    {
        // 10 items, page size 5 → 2 pages, on page 2
        var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_NotLastPage_ReturnsTrue()
    {
        // 10 items, page size 5 → 2 pages, on page 1
        var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
        Assert.IsTrue(list.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_SinglePage_ReturnsFalse()
    {
        // 3 items, page size 5 → 1 page, on page 1
        var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
        Assert.IsFalse(list.HasNextPage);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(4, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(10, result[4]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 15).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(1, result.PageIndex);
        Assert.AreEqual(3, result.TotalPages);
        Assert.AreEqual(5, result.Count);
        Assert.AreEqual(1, result[0]);
        Assert.AreEqual(5, result[4]);
    }

    [TestMethod]
    public void Create_LastPartialPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 2, 5);

        // Assert
        Assert.AreEqual(2, result.PageIndex);
        Assert.AreEqual(2, result.TotalPages);
        Assert.AreEqual(2, result.Count);
        Assert.AreEqual(6, result[0]);
        Assert.AreEqual(7, result[1]);
    }

    [TestMethod]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        // Arrange
        var source = Enumerable.Empty<int>().AsQueryable();

        // Act
        var result = PaginatedList<int>.Create(source, 1, 5);

        // Assert
        Assert.AreEqual(0, result.Count);
        Assert.AreEqual(0, result.TotalPages);
        Assert.IsFalse(result.HasPreviousPage);
        Assert.IsFalse(result.HasNextPage);
    }
}

