    {
        var dept = new Department { Name = "Math", Budget = 100000, StartDate = new DateTime(2020, 1, 1) };
        _context.Departments.Add(dept);
        _context.SaveChanges();
        return dept;
    }

    private (Instructor instructor, Course course) SeedInstructorWithCourse()
    {
        var dept = SeedDepartment();
        var instructor = SeedInstructor();

        var course = new Course
        {
            CourseID = 1001,
            Title = "Algebra",
            Credits = 3,
            DepartmentID = dept.DepartmentID,
            Enrollments = new List<Enrollment>()
        };
        _context.Courses.Add(course);
        _context.SaveChanges();

        var assignment = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
        _context.CourseAssignments.Add(assignment);
        _context.SaveChanges();

        // Reload navigation properties
        _context.Entry(instructor).Collection(i => i.CourseAssignments).Load();
        foreach (var ca in instructor.CourseAssignments)
        {
            _context.Entry(ca).Reference(c => c.Course).Load();
        }

        return (instructor, course);
    }

