        var count = GetProperty(result.Value, "count");
        Assert.AreEqual(0, count);
    }

    [TestMethod]
    public void GetNotifications_WithNotifications_ReturnsNotifications()
    {
        // Arrange - use a separate service instance (same static queue)
        using var service = new NotificationService();
        service.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);

        // Act
        var result = _controller.GetNotifications();

        // Assert
        Assert.IsNotNull(result);
        var success = GetProperty(result.Value, "success");
        Assert.AreEqual(true, success);
        var count = GetProperty(result.Value, "count");
        Assert.AreEqual(2, count);
    }

    [TestMethod]
    public void GetNotifications_LimitsTo10()
    {
        // Arrange - enqueue 15 notifications
        using var service = new NotificationService();
        for (int i = 0; i < 15; i++)
        {
            service.SendNotification("Item", i.ToString(), EntityOperation.CREATE);
        }

        // Act
        var result = _controller.GetNotifications();

        // Assert
        var count = GetProperty(result.Value, "count");
        Assert.AreEqual(10, count); // limited to 10 per the controller
    }

