    [TestCleanup]
    public void Cleanup()
    {
        _controller?.Dispose();
        _context?.Dispose();
    }

    private static object GetProperty(object obj, string name)
    {
        return obj.GetType().GetProperty(name)?.GetValue(obj);
    }

    [TestMethod]
    public void GetNotifications_EmptyQueue_ReturnsSuccessWithZeroCount()
    {
        // Act
