using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Data;
using System.Linq;

namespace ContosoUniversity.Tests;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsAllData()
    {
        // Arrange
        using var context = TestHelpers.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.Students.Count(), "Should seed 8 students");
        Assert.AreEqual(5, context.Instructors.Count(), "Should seed 5 instructors");
        Assert.AreEqual(4, context.Departments.Count(), "Should seed 4 departments");
        Assert.AreEqual(7, context.Courses.Count(), "Should seed 7 courses");
        Assert.AreEqual(3, context.OfficeAssignments.Count(), "Should seed 3 office assignments");
        Assert.AreEqual(8, context.CourseAssignments.Count(), "Should seed 8 course assignments");
        Assert.IsTrue(context.Enrollments.Count() > 0, "Should seed enrollments");
    }

    [TestMethod]
    public void Initialize_AlreadySeeded_DoesNotDuplicate()
    {
        // Arrange
        using var context = TestHelpers.CreateContext();
        DbInitializer.Initialize(context);
        var initialStudentCount = context.Students.Count();
        var initialInstructorCount = context.Instructors.Count();
        var initialDepartmentCount = context.Departments.Count();
        var initialCourseCount = context.Courses.Count();

        // Act - initialize again
        DbInitializer.Initialize(context);

        // Assert - counts should not change
        Assert.AreEqual(initialStudentCount, context.Students.Count(), "Student count should not change");
        Assert.AreEqual(initialInstructorCount, context.Instructors.Count(), "Instructor count should not change");
        Assert.AreEqual(initialDepartmentCount, context.Departments.Count(), "Department count should not change");
        Assert.AreEqual(initialCourseCount, context.Courses.Count(), "Course count should not change");
    }

    [TestMethod]
    public void Initialize_SeedsStudentsWithCorrectData()
    {
        // Arrange
        using var context = TestHelpers.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify specific seed data
        var alexander = context.Students.Single(s => s.LastName == "Alexander");
        Assert.AreEqual("Carson", alexander.FirstMidName);

        var li = context.Students.Single(s => s.LastName == "Li");
        Assert.AreEqual("Yan", li.FirstMidName);
    }

    [TestMethod]
    public void Initialize_SeedsDepartmentsWithInstructors()
    {
        // Arrange
        using var context = TestHelpers.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var english = context.Departments.Single(d => d.Name == "English");
        Assert.IsNotNull(english.InstructorID);

        var math = context.Departments.Single(d => d.Name == "Mathematics");
        Assert.IsNotNull(math.InstructorID);
    }

    [TestMethod]
    public void Initialize_SeedsCoursesWithDepartments()
    {
        // Arrange
        using var context = TestHelpers.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        Assert.AreEqual(1050, chemistry.CourseID);
        Assert.AreEqual(3, chemistry.Credits);

        var calculus = context.Courses.Single(c => c.Title == "Calculus");
        Assert.AreEqual(1045, calculus.CourseID);
        Assert.AreEqual(4, calculus.Credits);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        // Arrange
        using var context = TestHelpers.CreateContext();

        // Act
        DbInitializer.Initialize(context);

        // Assert - verify enrollment count and that some have grades
        var enrollments = context.Enrollments.ToList();
        Assert.AreEqual(11, enrollments.Count);

        var withGrades = enrollments.Count(e => e.Grade != null);
        Assert.IsTrue(withGrades > 0, "Some enrollments should have grades");

        var withoutGrades = enrollments.Count(e => e.Grade == null);
        Assert.IsTrue(withoutGrades > 0, "Some enrollments should have no grade");
    }
}

