+
+        // Assert
+        Assert.IsNotNull(result);
+        var success = GetProperty(result.Value, "success");
+        Assert.AreEqual(true, success);
+        var count = GetProperty(result.Value, "count");
+        Assert.AreEqual(2, count);
+    }
+
